-- tedw_release_summary
VALUES (
'
<span style="background-color: #9D0208; color: white; font-weight: bold; font-size: 18px; padding: 5px; display: inline-block; text-decoration: underline;">Release Summary - 07/15/2024 :</span>
<h4 style="margin-top: 0;">This release includes the following:</h4>
<ol>
    <li>Enhancements - 8
        <ul>
			<li>Datamart Enhancement - Added policy_history_sk to tpolicy_transaction, tdaily_inforce_policy, titem_inforce, titem_summary, tpolicy_summary, tpolicy_transaction_summary, tinternal_coverage_inforce, tinternal_coverage_summary tables</li>
			<li>Added Metal 07/13 release related 8 new columns for Auto</li>
			<li>Added Metal 07/13 release related 4 new columns for Home</li>
			<li>Added Metal 07/13 release related 7 new columns for PEL</li>
			<li>Added otc_ncrb_premium_amt and collision_ncrb_premium_amt column to tauto_policy_coverage table</li>
			<li>Deleted rater_pip_discount column from tauto_policy_coverage table and added to tauto_vehicle_coverage table</li>
			<li>Added vehicle_unique_id column to tquote_auto_vehicle and tquote_auto_vehicle_coverage tables </li>
			<li>Added primary_location_in column to tpel_location table </li>
		</ul>
    </li>
    <li>Bug tickets - 42
        <ul>
			<li>Deleted and rekeyed(by VC team) 29 NC Auto transactions so that the premium gets reflected appropriately under optional coverages (instead of taxes).Transaction issue date is updated to the original transaction issue date</li>
			<li>Data Standardization : Updated water_deductible, hurricane_deductible, hurricane_or_named_storm_deductible, wildfire_deductible, and wind_or_hailstorm_deductible with value $0 to null </li>
			<li>Data Standardization : Fixed aop_deductible, water_deductible, hurricane_deductible, wildfire_deductible, and wind_or_hailstorm_deductible amount which had formatting issues </li>
			<li>Data Standardization : Corrected metal field name "UninsuredUnderinsuredMotorist LiabilityForSecondaryInsured" to remove the extra space </li>
			<li>Backfilled NCRB Premiums for Collision and OTC on NC Auto policies </li>
			<li>Backfilled Rater PIP Discount on NC Auto policies </li>
            <li>Modified process to capture broker related changes accurately in tbroker table </li>
			<li>Modified procedure to update the policy term associated with OS data that had invalid values </li>
			<li>Modified procedure to capture disabled producer status </li>
			<li>Modified procedure to populate accurate premium modification factors for PEL policies </li>
			<li>Created alert for given set of requested policies </li>
			<li>Resolved 13 tickets associated with exclude_wind and hurricane/wind deductible fields </li>
			<li>Resolved 12 tickets associated with uninsured motorist BI/PD limit fields </li>
			<li>Resolved 4 tickets associated with underinsured motorist limit and limit type fields </li>
			<li>Updated values for extended_towing_and_labor_in, emergency_movement_coverage_in and physical_damage_deductible_adjustment for one policy </li>
			<li>Updated cape analytics view to to ensure proper data retrieval </li>
			<li>Updated city name and county name for one policy </li>
		</ul>
    </li>
</ol>
'
,'Yes'
,'2024-07-15'
,getdate()
,getdate()
)
;

-- tedw_release_note

